<?php require_once 'includes/config.php'; require_once 'includes/auth.php'; if (!has_permission([ROLE_ADMIN])) die('Acceso denegado.'); try { $pdo->exec('ALTER TABLE usuarios ADD COLUMN dni VARCHAR(20) DEFAULT NULL AFTER apellidos'); echo 'Columna DNI anadida correctamente a la tabla usuarios.'; } catch (PDOException $e) { if (strpos($e->getMessage(), 'Duplicate column name') !== false) { echo 'La columna DNI ya existe. Todo en orden.'; } else { echo 'Error al anadir la columna: ' . $e->getMessage(); } }
